sys_script_include.script:
var AROPCheckLibrary_SECOPS = Class.create();
AROPCheckLibrary_SECOPS.prototype = {
    initialize: function() {},
    _count: function(table, query) { var gr = new GlideRecord(table); if (query) gr.addEncodedQuery(query); gr.query(); return gr.getRowCount(); },
    _pct: function(num, den) { return den > 0 ? Math.round((num/den)*100) : 0; },
    CHK0000527: function() {
        try {
            return ((function() {
    var gr = new GlideRecord("sys_store_app");
    gr.addQuery("scope", "sn_si_gen_ai");
    gr.setLimit(1);
    gr.query();
    if (gr.next()) {
        return { status: "ready", actualValue: "Now Assist for Security Operations (sn_si_gen_ai) is active", finding: "Now Assist for Security Operations is active. AI-assisted security incident summarization, similar incident matching, and playbook recommendations are available." };
    }
    var gr2 = new GlideRecord("sys_plugins");
    gr2.addQuery("id", "sn_si_gen_ai");
    gr2.addQuery("active", true);
    gr2.setLimit(1);
    gr2.query();
    if (gr2.next()) {
        return { status: "ready", actualValue: "Now Assist for Security Operations (sn_si_gen_ai) is active", finding: "Now Assist for Security Operations is active. AI-assisted security incident summarization, similar incident matching, and playbook recommendations are available." };
    }
    return { status: "not_ready", actualValue: "Now Assist for Security Operations (sn_si_gen_ai) not found or inactive", finding: "Now Assist for Security Operations is not active. All Now Assist SIR AI capabilities are unavailable without this plugin." };
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000527: ' + e.message };
        }
    },
    CHK0000528: function() {
        try {
            return ((function() { var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-1); var ga = new GlideAggregate("sn_si_incident"); ga.addQuery("sys_created_on", ">=", cutoff.getValue()); ga.addAggregate("COUNT"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0; if (count >= 200) { return { status: "ready", actualValue: count + " security incidents in last 12 months", finding: count + " security incidents in the last 12 months. Sufficient history for Now Assist SIR AI summarization and similar incident pattern learning." }; } else if (count >= 50) { return { status: "needs_attention", actualValue: count + " security incidents in last 12 months", finding: "Only " + count + " security incidents in the last 12 months (target: 200+). Now Assist SIR AI learning will have limited pattern coverage." }; } else { return { status: "not_ready", actualValue: count + " security incidents in last 12 months", finding: "Only " + count + " security incidents in the last 12 months. Insufficient history for Now Assist SIR AI summarization and similar incident matching." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000528: ' + e.message };
        }
    },
    CHK0000529: function() {
        try {
            return ((function() { var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-1); var gaTotal = new GlideAggregate("sn_si_incident"); gaTotal.addQuery("state", "IN", "3,4"); gaTotal.addQuery("closed_at", ">=", cutoff.getValue()); gaTotal.addAggregate("COUNT"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate("COUNT")) : 0; if (total === 0) { return { status: "not_applicable", actualValue: "No closed security incidents in last 12 months", finding: "No closed security incidents found. Categorization cannot be assessed." }; } var gaCat = new GlideAggregate("sn_si_incident"); gaCat.addQuery("state", "IN", "3,4"); gaCat.addQuery("closed_at", ">=", cutoff.getValue()); gaCat.addQuery("category", "!=", ""); gaCat.addAggregate("COUNT"); gaCat.query(); var categorized = gaCat.next() ? parseInt(gaCat.getAggregate("COUNT")) : 0; var pct = Math.round((categorized / total) * 100); var actualValue = pct + "% of closed security incidents categorized (" + categorized + "/" + total + ")"; if (pct >= 85) { return { status: "ready", actualValue: actualValue, finding: pct + "% of closed security incidents have a category. Now Assist SIR has strong classification signal for AI routing and similar incident matching." }; } else if (pct >= 60) { return { status: "needs_attention", actualValue: actualValue, finding: "Only " + pct + "% of closed security incidents are categorized (target: 85%). Now Assist SIR AI routing accuracy will be reduced." }; } else { return { status: "not_ready", actualValue: actualValue, finding: "Only " + pct + "% of security incidents are categorized. Insufficient classification signal for Now Assist SIR AI routing." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000529: ' + e.message };
        }
    },
    CHK0000530: function() {
        try {
            return ((function() { var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-1); var gaTotal = new GlideAggregate("sn_si_incident"); gaTotal.addQuery("state", "IN", "3,4"); gaTotal.addQuery("closed_at", ">=", cutoff.getValue()); gaTotal.addAggregate("COUNT"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate("COUNT")) : 0; if (total === 0) { return { status: "not_applicable", actualValue: "No closed security incidents in last 12 months", finding: "No closed security incidents found. Close notes coverage cannot be assessed." }; } var gaMissing = new GlideAggregate("sn_si_incident"); gaMissing.addQuery("state", "IN", "3,4"); gaMissing.addQuery("closed_at", ">=", cutoff.getValue()); gaMissing.addQuery("close_notes", ""); gaMissing.addAggregate("COUNT"); gaMissing.query(); var missing = gaMissing.next() ? parseInt(gaMissing.getAggregate("COUNT")) : 0; var populated = total - missing; var pct = Math.round((populated / total) * 100); var actualValue = pct + "% of closed security incidents have close notes (" + populated + "/" + total + ")"; if (pct >= 85) { return { status: "ready", actualValue: actualValue, finding: pct + "% of closed security incidents have close notes. Now Assist SIR summarization has strong resolution context for AI-generated summaries." }; } else if (pct >= 60) { return { status: "needs_attention", actualValue: actualValue, finding: "Only " + pct + "% of closed security incidents have close notes (target: 85%). Now Assist SIR summarization quality will be reduced." }; } else { return { status: "not_ready", actualValue: actualValue, finding: "Only " + pct + "% of security incidents have close notes. Now Assist SIR cannot generate meaningful incident summaries without resolution context." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000530: ' + e.message };
        }
    },
    CHK0000531: function() {
        try {
            return ((function() { var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-1); var usedGroups = {}; var gr = new GlideRecord("sn_si_incident"); gr.addQuery("sys_created_on", ">=", cutoff.getValue()); gr.addQuery("assignment_group", "!=", ""); gr.query(); while (gr.next()) { usedGroups[gr.getValue("assignment_group")] = true; } var groupIds = Object.keys(usedGroups); var totalGroups = groupIds.length; if (totalGroups === 0) { return { status: "not_ready", actualValue: "No assignment groups used on security incidents in last 12 months", finding: "No assignment groups found on security incidents. Now Assist SIR AI routing has no group structure to route incidents to." }; } var groupsWithMembers = 0; for (var i = 0; i < groupIds.length; i++) { var memGr = new GlideRecord("sys_user_grmember"); memGr.addQuery("group", groupIds[i]); memGr.setLimit(1); memGr.query(); if (memGr.next()) groupsWithMembers++; } var pct = Math.round((groupsWithMembers / totalGroups) * 100); var actualValue = totalGroups + " security assignment groups | " + groupsWithMembers + " with active members (" + pct + "%)"; if (groupsWithMembers >= 2 && pct >= 80) { return { status: "ready", actualValue: actualValue, finding: groupsWithMembers + " populated security assignment groups. Now Assist SIR AI routing has well-defined staffed groups to route incidents to." }; } else if (groupsWithMembers >= 1) { return { status: "needs_attention", actualValue: actualValue, finding: "Only " + groupsWithMembers + " of " + totalGroups + " security assignment groups have members. Now Assist SIR AI routing may attempt to assign incidents to empty groups." }; } else { return { status: "not_ready", actualValue: actualValue, finding: "No security assignment groups have active members. Now Assist SIR AI routing cannot function without populated assignment groups." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000531: ' + e.message };
        }
    },
    CHK0000532: function() {
        try {
            return (function() {
    var t = new GlideRecord("sys_pd_process_definition");
    if (!t.isValid()) {
        return { status: "value_blocker", actualValue: "Required table sys_pd_process_definition not found", finding: "Process Automation Designer table is not available. Verify the Security Incident Response plugin is active." };
    }
    var ga = new GlideAggregate("sys_pd_process_definition");
    ga.addQuery("sys_scope.scope", "sn_si");
    ga.addQuery("active", true);
    ga.addAggregate("COUNT");
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;
    if (count >= 5) {
        return { status: "ready", actualValue: count + " active security playbooks configured", finding: count + " active security playbooks. Now Assist SIR can recommend AI-matched playbooks based on incident type and threat category." };
    } else if (count >= 1) {
        return { status: "needs_attention", actualValue: count + " active security playbooks configured", finding: "Only " + count + " active security playbook(s) (target: 5+). Now Assist SIR playbook recommendations will have limited coverage across incident types." };
    } else {
        return { status: "value_blocker", actualValue: "No active security playbooks found", finding: "No active security playbooks configured. Now Assist SIR cannot recommend playbooks without defined response procedures." };
    }
})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000532: ' + e.message };
        }
    },
    CHK0000533: function() {
        try {
            return ((function() { var ga = new GlideAggregate("sla"); ga.addQuery("table", "CONTAINS", "sn_si_incident"); ga.addQuery("active", true); ga.addAggregate("COUNT"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0; if (count >= 3) { return { status: "ready", actualValue: count + " active security incident SLA definitions", finding: count + " active security SLAs. Now Assist SIR can prioritize incidents using AI-driven SLA breach risk analysis." }; } else if (count >= 1) { return { status: "needs_attention", actualValue: count + " active security incident SLA(s)", finding: "Only " + count + " active security SLA(s) (target: 3+). Now Assist SIR SLA-based AI prioritization will have limited differentiation across incident severity levels." }; } else { return { status: "not_ready", actualValue: "No active security incident SLAs defined", finding: "No active security incident SLAs. Now Assist SIR cannot differentiate incident urgency for AI prioritization without SLA definitions." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000533: ' + e.message };
        }
    },
    CHK0000534: function() {
        try {
            return ((function() { var gr = new GlideRecord("sys_scope"); gr.addQuery("scope", "sn_si_workspace"); gr.addQuery("active", true); gr.setLimit(1); gr.query(); if (gr.next()) { return { status: "ready", actualValue: "Security Incident Workspace (sn_si_workspace) is active", finding: "Security Incident Workspace is active. Now Assist SIR AI insights including incident summaries and playbook recommendations are surfaced in context for analysts." }; } return { status: "not_ready", actualValue: "Security Incident Workspace (sn_si_workspace) not found or inactive", finding: "Security Incident Workspace is not active. Now Assist SIR AI insights are not accessible in a contextually relevant interface." }; }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000534: ' + e.message };
        }
    },
    CHK0000535: function() {
        try {
            return ((function() { var gaBR = new GlideAggregate("sys_script"); gaBR.addQuery("collection", "sn_si_incident"); gaBR.addQuery("active", true); gaBR.addQuery("sys_created_by", "NOT IN", "glide.maint,system,admin,fred.luddy"); gaBR.addAggregate("COUNT"); gaBR.query(); var brs = gaBR.next() ? parseInt(gaBR.getAggregate("COUNT")) : 0; var gaCS = new GlideAggregate("sys_script_client"); gaCS.addQuery("table", "sn_si_incident"); gaCS.addQuery("active", true); gaCS.addQuery("sys_created_by", "NOT IN", "glide.maint,system,admin,fred.luddy"); gaCS.addAggregate("COUNT"); gaCS.query(); var cs = gaCS.next() ? parseInt(gaCS.getAggregate("COUNT")) : 0; var risk = brs + cs; var actualValue = brs + " custom BRs + " + cs + " client scripts on sn_si_incident (risk score: " + risk + ")"; if (risk <= 5) { return { status: "ready", actualValue: actualValue, finding: "Low security incident customization risk (score: " + risk + "). Now Assist SIR AI Agent actions are unlikely to encounter conflicts." }; } else if (risk <= 10) { return { status: "needs_attention", actualValue: actualValue, finding: "Moderate security incident customization risk (score: " + risk + "). Test Now Assist SIR in sub-production before enabling in production." }; } else { return { status: "not_ready", actualValue: actualValue, finding: "High security incident customization risk (score: " + risk + "). Extensive customization increases the risk of conflicts with Now Assist SIR AI Agent actions." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000535: ' + e.message };
        }
    },
    CHK0000536: function() {
        try {
            return ((function() { var cutoff = new GlideDateTime(); cutoff.addDaysUTC(-90); var gaTotal = new GlideAggregate("sn_si_incident"); gaTotal.addQuery("sys_created_on", ">=", cutoff.getValue()); gaTotal.addAggregate("COUNT"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate("COUNT")) : 0; if (total === 0) { return { status: "not_applicable", actualValue: "No security incidents in last 90 days", finding: "No security incidents found in the last 90 days. Alert linkage cannot be assessed." }; } var gaLinked = new GlideAggregate("sn_si_incident"); gaLinked.addQuery("sys_created_on", ">=", cutoff.getValue()); gaLinked.addQuery("alert", "!=", ""); gaLinked.addAggregate("COUNT"); gaLinked.query(); var linked = gaLinked.next() ? parseInt(gaLinked.getAggregate("COUNT")) : 0; var pct = Math.round((linked / total) * 100); var actualValue = pct + "% of security incidents linked to alerts (last 90 days, " + linked + "/" + total + ")"; if (pct >= 50) { return { status: "ready", actualValue: actualValue, finding: pct + "% of security incidents are linked to alerts. Now Assist SIR has rich alert context for AI impact analysis and attack pattern recognition." }; } else if (pct >= 20) { return { status: "needs_attention", actualValue: actualValue, finding: "Only " + pct + "% of security incidents are linked to alerts (target: 50%+). Now Assist SIR AI impact analysis will have limited alert context." }; } else { return { status: "not_ready", actualValue: actualValue, finding: "Only " + pct + "% of security incidents are linked to alerts. Now Assist SIR cannot perform meaningful AI attack pattern recognition without alert-to-incident linkage." }; } }))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000536: ' + e.message };
        }
    },
    type: 'AROPCheckLibrary_SECOPS'
};
